mapper.select:
SELECT * FROM ( SELECT /* @SQLID=SUB0201_02-01#Sql001 */ COUNT(1) OVER() AS totalRow , A.TC_COMP_RANK AS tcCompRank , A.NAME_KANA AS customerNameKana , A.NAME_KANJI AS customerNameKanji , A.ACCOUNT_NUMBER AS accountNumber , E.BROKER_BRANCH_CODE AS branchCode , A.BROKER_CODE AS brokerCode , A.INTERMEDIARY_EMP_CD AS brokerChargeCode , A.BUTEN_CODE AS butenCode , E.BROKER_CHARGE_NAME AS chargeName , E.BRANCH_NAME AS branchName , C.BRANCH_NAME AS brokerName , G.PROF_LOSS_TRUST_STOCK AS customerListProfitAndLossOfMarginPosition , I.DEFICIT_STATUS AS marginStatus , I.CHARGE_FLG AS chargeFlag , J.ACCEPTANCE_DEPOSIT AS acceptanceDeposit , J.MAINTAIN_RATE AS maintenanceRate , H.CUSTOMER_ATTRIBUTE_NAME AS customerAttributeName , K.TENGUN AS tengun FROM MEDIATE_USER_ATTRIBUTE_INFO A LEFT JOIN MEDIATE_BRANCH C ON A.BROKER_CODE = C.BROKER_CODE AND C.BROKER_BRANCH_KIND = '00' LEFT JOIN V_MEDIATE_CHARGE_INFO E ON A.BROKER_CODE = E.BROKER_CODE AND A.INTERMEDIARY_EMP_CD = E.BROKER_CHARGE_CODE LEFT JOIN USER_ATTRIBUTE G ON A.CUSTOMER_ID = G.CUSTOMER_ID LEFT JOIN CUSTOMER_ATTRIBUTE_MASTER H ON A.CUSTOMER_ATTRIBUTE = H.CUSTOMER_ATTRIBUTE LEFT JOIN USER_DEFICIT_INFO I ON A.BUTEN_CODE = I.BUTEN_CODE AND A.ACCOUNT_NUMBER = I.ACCOUNT_NUMBER LEFT JOIN T_MARGIN_CALL J ON A.BUTEN_CODE = J.BUTEN_CODE AND A.ACCOUNT_NUMBER = TO_NUMBER(J.ACCOUNT_NUMBER) LEFT JOIN BRANCH_MASTER K ON A.BUTEN_CODE = K.BRANCH_CODE WHERE A.UAI_ACCT_CLASS_FLG1 = '1'
AND A.BROKER_CODE NOT IN
#{chargeCode}
AND A.BROKER_CODE IN
#{chargeCode}
AND E.BROKER_BRANCH_CODE = #{req.branchCode}
AND A.INTERMEDIARY_EMP_CD = #{req.empCode}
AND(A.BROKER_CODE IN
) OR A.BROKER_CODE IN(
,
#{brokerChargeList.brokerCode}
)
AND((A.BROKER_CODE, A.INTERMEDIARY_EMP_CD) IN
) OR (A.BROKER_CODE, A.INTERMEDIARY_EMP_CD) IN(
,
(#{brokerChargeList.brokerCode},#{brokerChargeList.empCode})
)
AND A.BUTEN_CODE = #{req.butenCode}
AND A.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND( REGEXP_LIKE(A.NAME_KANJI, #{req.customerNameKanjiKana}) OR REGEXP_LIKE(A.NAME_KANA, #{req.customerNameKanjiKana}) )
AND H.CUSTOMER_ATTRIBUTE IN
#{course}
AND G.PROF_LOSS_TRUST_STOCK >= #{req.beforeProfitAndLossFrom}
AND G.PROF_LOSS_TRUST_STOCK <= #{req.beforeProfitAndLossTo}
AND J.ACCEPTANCE_DEPOSIT >= #{req.beforeDepositBalanceFrom}
AND J.ACCEPTANCE_DEPOSIT <= #{req.beforeDepositBalanceTo}
AND J.MAINTAIN_RATE >= #{req.beforeEntrustDepositRateFrom}
AND J.MAINTAIN_RATE <= #{req.beforeEntrustDepositRateTo}
AND I.DEFICIT_STATUS <> '0'
AND I.CHARGE_FLG = #{req.withdrawalDeficientCheck}
ORDER BY brokerCode, butenCode, accountNumber ASC ) WHERE ROWNUM <= #{req.rowNum}
